526	  function psi_fix_upper_bound_stdlv(fmt : psi_fix_fmt_t)
527	  return std_logic_vector is
528	  begin
529	    return cl_fix_max_value(psi_fix2_cl_fix(fmt));
530	  end function;
531	
532	  -- *** psi_fix_lower_bound_stdlv ***
533	  function psi_fix_lower_bound_stdlv(fmt : psi_fix_fmt_t)
534	  return std_logic_vector is
535	  begin
536	    return cl_fix_min_value(psi_fix2_cl_fix(fmt));
537	  end function;
538	
539	  -- *** psi_fix_upper_bound_Real ***
540	  function psi_fix_upper_bound_Real(fmt : psi_fix_fmt_t)
541	  return real is
542	  begin
543	    return cl_fix_max_real(psi_fix2_cl_fix(fmt));
544	  end function;
545	
546	  -- *** psi_fix_lower_bound_Real ***
547	  function psi_fix_lower_bound_Real(fmt : psi_fix_fmt_t)
548	  return real is
549	  begin
550	    return cl_fix_min_real(psi_fix2_cl_fix(fmt));
551	  end function;
552	
553	  -- *** psi_fix_in_range ***
554	  function psi_fix_in_range(a    : std_logic_vector;
555	                         a_fmt : psi_fix_fmt_t;
556	                         r_fmt : psi_fix_fmt_t;
557	                         rnd  : psi_fix_rnd_t := psi_fix_trunc)
558	  return boolean is
559	  begin
560	    return cl_fix_in_range(a, psi_fix2_cl_fix(a_fmt), psi_fix2_cl_fix(r_fmt), psi_fix2_cl_fix(rnd));
561	  end function;
562	
563	  -- *** psi_fix_round_from_string ***
564	  function psi_fix_round_from_string(s : string)
565	  return psi_fix_rnd_t is
566	  begin
567	    if s = "psi_fix_round" or s = "psifixround" then
568	      return psi_fix_round;
569	    elsif s = "psi_fix_trunc" or s = "psifixtrunc" then
570	      return psi_fix_trunc;
571	    end if;
572	    report "psi_fix_round_from_string: Illegal value - " & s severity error;
573	    return psi_fix_trunc;
574	  end function;
575	
576	  -- *** psi_fix_sat_from_string ***
577	  function psi_fix_sat_from_string(s : string)
578	  return psi_fix_sat_t is
579	  begin
580	    if s = "psi_fix_sat" or s = "psifixsat" then
581	      return psi_fix_sat;
582	    elsif s = "psi_fix_wrap" or s = "psifixwrap" then
583	      return psi_fix_wrap;
584	    end if;
585	    report "psi_fix_sat_from_string: Illegal value - " & s severity error;
586	    return psi_fix_wrap;
587	  end function;
588	
589	  -- *** psi_fix_compare ***
590	  -- Allowed comparisons: "a=b", "a<b", "a>b", "a<=b", "a>=b", "a!=b"
591	  function psi_fix_compare(comparison : string;
592	                         a          : std_logic_vector;
593	                         a_fmt       : psi_fix_fmt_t;
594	                         b          : std_logic_vector;
595	                         b_fmt       : psi_fix_fmt_t) return boolean is
596	  begin
597	    return cl_fix_compare(comparison, a, psi_fix2_cl_fix(a_fmt), b, psi_fix2_cl_fix(b_fmt));
598	  end function;
599	
600	  -- *** psi_fix_fmt_from_string ***
601	  function psi_fix_fmt_from_string(str : string) return psi_fix_fmt_t is
602	    variable Format_v         : psi_fix_fmt_t;
603	    variable OpenBraceIdx_v   : integer := -1;
604	    variable FirstCommaIdx_v  : integer := -1;
605	    variable SecondCommaIdx_v : integer := -1;
606	    variable CloseBraceIdx_v  : integer := -1;
607	  begin
608	    -- Parse Format
609	    for i in str'low to str'high loop
610	      if (OpenBraceIdx_v = -1) and (str(i) = '(') then
611	        OpenBraceIdx_v := i;
612	      elsif (FirstCommaIdx_v = -1) and (str(i) = ',') then
613	        FirstCommaIdx_v := i;
614	      elsif (SecondCommaIdx_v = -1) and (str(i) = ',') then
615	        SecondCommaIdx_v := i;
616	      elsif (CloseBraceIdx_v = -1) and (str(i) = ')') then
617	        CloseBraceIdx_v := i;
618	      end if;
619	    end loop;
620	    assert OpenBraceIdx_v >= 0 report "psi_fix_fmt_from_string: No opening brace found" severity error;
621	    assert FirstCommaIdx_v >= 0 report "psi_fix_fmt_from_string: First comma not found" severity error;
622	    assert SecondCommaIdx_v >= 0 report "psi_fix_fmt_from_string: Second comman not found" severity error;
623	    assert CloseBraceIdx_v >= 0 report "psi_fix_fmt_from_string: No closing brace found" severity error;
624	    Format_v.S := psi_fix_str_to_int(str(OpenBraceIdx_v + 1 to FirstCommaIdx_v - 1));
625	    Format_v.I := psi_fix_str_to_int(str(FirstCommaIdx_v + 1 to SecondCommaIdx_v - 1));
626	    Format_v.F := psi_fix_str_to_int(str(SecondCommaIdx_v + 1 to CloseBraceIdx_v - 1));
627	    assert (Format_v.S = 0) or (Format_v.S = 1) report "psi_fix_fmt_from_string: Sign must be 1 or 0" severity error;
628	    return Format_v;
629	  end function;
630	
631	  -- *** psi_fix_fmt_to_string ***
632	  function psi_fix_fmt_to_string(a_fmt : psi_fix_fmt_t) return string is
633	  begin
634	    return "(" & integer'image(a_fmt.S) & ", " & integer'image(a_fmt.I) & ", " & integer'image(a_fmt.F) & ")";
635	  end function;
636	
637	end psi_fix_pkg;
638	
